import subprocess, sys, time, os, re, json
import urllib.request

BIN = "/home/kamilner/tamarin-rs/tamarin-prover-testing/.stack-work/install/x86_64-linux-tinfo6/ec0cb11b1bfcf8776d45e0357bbc6d6ff2077f9222735af22115429c8cdfcef1/9.6.7/bin/tamarin-prover"
os.environ["PATH"] = "/home/linuxbrew/.linuxbrew/bin:" + os.environ.get("PATH","")

def get(url, timeout=30):
    try:
        with urllib.request.urlopen(url, timeout=timeout) as r:
            return r.status, r.read().decode('utf-8','replace')
    except Exception as e:
        return None, str(e)

def serve_one(spthy, port):
    d = subprocess.run(["mktemp","-d"], capture_output=True, text=True).stdout.strip()
    subprocess.run(["cp", spthy, d+"/"])
    log = open(f"/tmp/drive_{port}.log","w")
    p = subprocess.Popen([BIN,"interactive",d,f"--port={port}"], stdout=log, stderr=subprocess.STDOUT)
    return p

def wait_loaded(port, tries=40):
    for _ in range(tries):
        st, body = get(f"http://127.0.0.1:{port}/")
        if st == 200 and "/thy/trace/1/overview/help" in body:
            return True
        time.sleep(0.5)
    return False

def solve_and_graph(port, lemma="go"):
    # autoprove
    st, body = get(f"http://127.0.0.1:{port}/thy/trace/1/autoprove/idfs/0/False/proof/{lemma}")
    m = re.search(r'/thy/trace/(\d+)/', body)
    idx = m.group(1) if m else "1"
    st, g = get(f"http://127.0.0.1:{port}/thy/trace/{idx}/interactive-graph-def/proof/{lemma}/_")
    return st, g

def extract_fact(dot, functor="Out"):
    i = dot.find(functor + "(")
    if i < 0:
        return None
    # take until the cell delimiter | or } that ends the record cell.
    # We capture the whole label and find the balanced-ish fact; simplest: up to '|' or '}}"'
    j = i
    depth = 0
    # walk until we hit an unescaped | or } at record level: the fact ends before | or }
    rest = dot[i:i+2000]
    # cut at first occurrence of '|<' (next cell) or '}|' or '}}"' terminators
    for term in ['|<n', '}|{', '}}"']:
        k = rest.find(term)
        if k != -1:
            rest = rest[:k+ (1 if term=='}}"' else 0)]
            break
    return rest

def lines_of(fact):
    parts = fact.split(r'\l')
    out = []
    for p in parts:
        m = re.match(r'((?:&nbsp;)*)', p)
        indent = len(m.group(1))//6
        disp = p.replace('&nbsp;','').replace(r'\<','<').replace(r'\>','>').replace(r'\{','{').replace(r'\}','}').replace(r'\|','|')
        out.append((indent, len(disp), disp))
    # drop a trailing empty line from trailing \l
    while out and out[-1][2]==0:
        out.pop()
    return out

if __name__ == '__main__':
    outdir = sys.argv[1]
    port = int(sys.argv[2])
    files = sorted(sys.argv[3:])
    results = {}
    for f in files:
        p = serve_one(f, port)
        try:
            if not wait_loaded(port):
                print(f"{os.path.basename(f)}: LOAD FAILED"); continue
            st, dot = solve_and_graph(port)
            fact = extract_fact(dot)
            if fact is None:
                print(f"{os.path.basename(f)}: no Out fact (st={st}, bytes={len(dot)})"); continue
            L = lines_of(fact)
            flat_first = L[0][1]
            nbreaks = len(L)-1
            firstline = L[0][2]
            print(f"{os.path.basename(f)}: nlines={len(L)} firstlen={firstline and len(firstline)} :: " +
                  " || ".join(f"[i{ind}|{ln}]{disp}" for ind,ln,disp in L))
            results[os.path.basename(f)] = L
        finally:
            p.terminate()
            try: p.wait(timeout=5)
            except: p.kill()
            time.sleep(0.3)
    json.dump({k:[list(x) for x in v] for k,v in results.items()}, open(f"{outdir}/results.json","w"), indent=1)

