27	/// Escape the metacharacters that are special inside a graphviz record label:
28	/// `< > { } |` each get a leading backslash. Everything else (including single
29	/// quotes, `~ $ ^ * ⊕`, spaces) is literal. Observed in every record cell.
30	pub fn escape_record(s: &str) -> String {
31	    let mut out = String::with_capacity(s.len());
32	    for c in s.chars() {
33	        match c {
34	            '<' | '>' | '{' | '}' | '|' => {
35	                out.push('\\');
36	                out.push(c);
37	            }
38	            _ => out.push(c),
39	        }
40	    }
41	    out
42	}
