75	/// Fact spacing `Name( a, b )`, collapsing to `Name( )` for zero arguments
76	/// (observed: `NoA( )`, `!Semistate_1( )` — a single space between the parens).
77	fn pad(name: &str, args: &[String]) -> String {
78	    if args.is_empty() {
79	        format!("{}( )", name)
80	    } else {
81	        format!("{}( {} )", name, args.join(", "))
82	    }
83	}
