86	/// has action facts, `[<action>, …]`. Matches the observed info-cell shape
87	/// (`#i : I_Complete[Complete( … ), …]`, or a bare `#vf.5 : Fresh`).
88	pub fn render_info(temporal: &str, rule: &str, actions: &[Fact]) -> String {
89	    if actions.is_empty() {
90	        format!("#{} : {}", temporal, rule)
91	    } else {
92	        let acts: Vec<String> = actions.iter().map(Fact::render_flat).collect();
93	        format!("#{} : {}[{}]", temporal, rule, acts.join(", "))
94	    }
